const items = $input.all();
const periodo = $('Execute Sub-workflow Trigger').item.json.periodo;

const categorias = items.filter(item => item.json.total != null);

if (categorias.length === 0) {
  const labels = { hoy: 'hoy', semana: 'esta semana', mes: 'este mes' };
  const label = labels[periodo] || periodo;
  return [{ json: { output: `No hay gastos registrados ${label}.` } }];
}

const totalGeneral = categorias.reduce((sum, item) => sum + parseFloat(item.json.total), 0);

const desglose = categorias
  .map(item => `  • ${item.json.categoria}: $${parseFloat(item.json.total).toFixed(2)}`)
  .join('\n');

const labels = { hoy: 'de hoy', semana: 'de esta semana', mes: 'de este mes' };
const label = labels[periodo] || `del período: ${periodo}`;

const output = `Resumen ${label}:\nTotal: $${totalGeneral.toFixed(2)}\n\nPor categoría:\n${desglose}`;

return [{ json: { output } }];
